import os
from fastapi import FastAPI, Depends, HTTPException
from fastapi.security import OAuth2PasswordBearer, OAuth2PasswordRequestForm
from redis import Redis

app = FastAPI()

# Set up the OAuth2PasswordBearer security scheme
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="token")

# Set up the Redis cache
redis = Redis.from_url(os.environ["REDIS_URL"])

# Define a dependency injection pattern for token validation
def get_token(token: str = Depends(oauth2_scheme)):
    # Check if the token exists in the Redis cache
    if redis.exists(token):
        return token
    else:
        raise HTTPException(status_code=401, detail="Invalid or expired token")

# Define a protected endpoint that requires authentication
@app.get("/protected")
async def read_protected(token: str = Depends(get_token)):
    # Do something with the authenticated user's information
    return {"hello": "world"}